import { useCallback, useEffect, useState } from 'react';
import { Box, Flex } from '@chakra-ui/react';
import { useTranslation } from 'react-i18next';
import { BankAccountCreation } from '@domain/bankAccount';
import { YodleeVerification } from '@domain/yodlee';
import { useGetAccount } from '@state/accounts';
import {
  useCreateBankAccount,
  useCreateYodleeBankAccount,
  useGetAllBankAccounts,
  useUpdateBankAccount,
} from '@state/bank_accounts/helpers';
import { useReplaceBankAccount } from '@state/bank_accounts/helpers/useReplaceBankAccount';
import { useFeatureFlag } from '@state/featureFlags';
import { useCreateVerifiedBankAccount } from '@state/org/verified_bank_accounts';
import { useCreatePlaidBankAccount } from '@state/public/plaid';
import { usePermissions } from '@state/utils';
import { BackButton, Button } from '@ui/components/Button';
import { Loading } from '@ui/components/Loading';
import { Panel } from '@ui/components/Panel';
import { useToast } from '@ui/components/Toast';
import {
  ManualEntryStep,
  SchedulingStep,
  YodleeStep,
} from '@ui/components/forms/AddBankAccountForms';
import { Heading, Paragraph } from '@ui/components/typography';
import { usePlaid } from '@utils/usePlaid/usePlaid';
import { StepFooter } from '../StepFooter';
import { useSteps } from '../useSteps';
import { HeaderDisclaimers } from './HeaderDisclaimers';
import { ReplaceBankAccount } from './ReplaceBankAccount';

type Step = 'yodlee' | 'plaid' | 'manualEntry' | 'scheduling';
const MANUAL_ENTRY_FORM_ID = 'manual-entry-form-id';
const SCHEDULING_FORM_ID = 'scheduling-form-id';

export const ConnectBank = () => {
  const enablePlaidLink = useFeatureFlag('settings.usePlaidBankAccountVerification');
  const { bankAccounts, isLoadingBankAccounts } = useGetAllBankAccounts();
  const { bankAccountCreationError, createBankAccountAsync, isCreatingBankAccount } =
    useCreateBankAccount();
  const { createYodleeBankAccountAsync, isCreatingYodleeBankAccount } =
    useCreateYodleeBankAccount();
  const { replaceBankAccountAsync } = useReplaceBankAccount();
  const { bankAccountUpdateError, isUpdatingBankAccount, updateBankAccount } =
    useUpdateBankAccount();
  const { canManageGrossDeposits } = usePermissions();
  const mostRecentBankAccount = bankAccounts?.slice(-1)[0];
  const { navigateNextStep } = useSteps();
  const { currentAccount } = useGetAccount();
  const { showToast } = useToast();

  const { createPlaidBankAccount, isLoading: isCreatingPlaidBankAccount } =
    useCreatePlaidBankAccount();

  const { createVerifiedBankAccount, isLoading: isCreatingVerifiedBankAccount } =
    useCreateVerifiedBankAccount();

  const [step, setStep] = useState<Step | null>(null);

  useEffect(() => {
    if (!step && !!bankAccounts) {
      setStep(!bankAccounts?.length ? (enablePlaidLink ? 'plaid' : 'yodlee') : 'scheduling');
    }
  }, [bankAccounts, enablePlaidLink, step]);

  const { t } = useTranslation('organizationApplication', { keyPrefix: 'bankAccount' });

  const createOrReplaceBankAccount = useCallback(
    async (bankAccount: Omit<BankAccountCreation, 'accountId'>) => {
      const currentId = mostRecentBankAccount?.id;
      const newAccount = await createBankAccountAsync(bankAccount);

      if (currentId) {
        await replaceBankAccountAsync({
          newBankAccountId: newAccount.id,
          oldBankAccountId: currentId,
        });
      }

      setStep('scheduling');
    },
    [mostRecentBankAccount, createBankAccountAsync, replaceBankAccountAsync]
  );

  const createOrReplaceYodleeBankAccount = useCallback(
    async (accountDetails: YodleeVerification) => {
      const newAccount = await createYodleeBankAccountAsync({ yodleeAccountId: accountDetails.id });

      const currentId = mostRecentBankAccount?.id;

      if (currentId) {
        await replaceBankAccountAsync({
          newBankAccountId: newAccount.id,
          oldBankAccountId: currentId,
        });
      }

      setStep('scheduling');
    },
    [mostRecentBankAccount, createYodleeBankAccountAsync, replaceBankAccountAsync]
  );

  const onLinkPlaid = useCallback(
    (publicToken) => {
      createPlaidBankAccount({ publicToken })
        .then((bankAccount) => createVerifiedBankAccount(bankAccount.id))
        .then(async (bankAccount) => {
          const currentId = mostRecentBankAccount?.id;

          if (currentId) {
            await replaceBankAccountAsync({
              newBankAccountId: bankAccount.id,
              oldBankAccountId: currentId,
            });
          }

          setStep('scheduling');
        })
        .catch((error) => {
          console.error(error);

          showToast({
            message: t('verificationFailure'),
            variant: 'error',
          });

          setStep('manualEntry');
        });
    },
    [
      createPlaidBankAccount,
      createVerifiedBankAccount,
      mostRecentBankAccount?.id,
      replaceBankAccountAsync,
      showToast,
      t,
    ]
  );

  const {
    open: openPlaidLink,
    ready: isPlaidLinkReady,
    token: plaidLinkToken,
  } = usePlaid({ onSuccess: onLinkPlaid });

  if (!currentAccount || (isLoadingBankAccounts && !bankAccounts?.length)) {
    return <Loading />;
  }

  return (
    <Flex direction="column" gap={4}>
      <hgroup>
        <Heading as="h1">{t('heading')}</Heading>
        <Paragraph as="h2">{currentAccount.displayName}</Paragraph>
      </hgroup>
      <Panel as={Flex} flexDirection="column" gap={6} p={6} variant="primary">
        {step === 'manualEntry' && (
          <Box>
            <BackButton onClick={() => setStep(enablePlaidLink ? 'plaid' : 'yodlee')}>
              {t('manualEntryBackButton')}
            </BackButton>
          </Box>
        )}

        <HeaderDisclaimers />

        {step === 'yodlee' && (
          <YodleeStep
            onManualClick={() => setStep('manualEntry')}
            onSuccess={createOrReplaceYodleeBankAccount}
          />
        )}

        {step === 'plaid' ? (
          <>
            <Button
              isDisabled={!isPlaidLinkReady || !plaidLinkToken}
              isLoading={isCreatingPlaidBankAccount || isCreatingVerifiedBankAccount}
              onClick={() => openPlaidLink()}
              size="lg"
              variant="secondary"
              width="full"
            >
              {t('connectBank')}
            </Button>

            <Button
              onClick={() => setStep('manualEntry')}
              size="md"
              variant="tertiary"
              width="full"
            >
              {t('connectBankManually')}
            </Button>
          </>
        ) : null}

        {step === 'manualEntry' && (
          <ManualEntryStep
            formId={MANUAL_ENTRY_FORM_ID}
            hideBackButton
            onSubmit={createOrReplaceBankAccount}
            serverError={bankAccountCreationError}
          />
        )}

        {step === 'scheduling' && !!mostRecentBankAccount && (
          <SchedulingStep
            bankAccount={mostRecentBankAccount}
            bankAccountFundCount={0}
            canManageGrossDepositsAndMonthlyReconcile={canManageGrossDeposits}
            formId={SCHEDULING_FORM_ID}
            headerAction={
              <ReplaceBankAccount
                bankAccount={mostRecentBankAccount}
                onReplaceBankAccount={() => setStep(enablePlaidLink ? 'plaid' : 'yodlee')}
              />
            }
            isSimplified
            onSubmit={(bankAccount) =>
              updateBankAccount(
                {
                  ...bankAccount,
                  default: true,
                  frequency: +bankAccount.depositSchedule,
                  id: mostRecentBankAccount.id,
                },
                { onSuccess: () => navigateNextStep() }
              )
            }
            serverError={bankAccountUpdateError}
          />
        )}
      </Panel>
      <StepFooter
        formId={step === 'manualEntry' ? MANUAL_ENTRY_FORM_ID : SCHEDULING_FORM_ID}
        isLoading={isCreatingBankAccount || isCreatingYodleeBankAccount || isUpdatingBankAccount}
      />
    </Flex>
  );
};
