import { InlineBillingAgreement } from '@domain/billingAgreement';

export const computeTotalFees = ({
  amount,
  billingAgreements,
  cardType,
  isInternational = false,
  paymentType,
}: {
  amount?: number | null;
  billingAgreements?: InlineBillingAgreement[];
  cardType?: 'american-express' | 'visa' | 'mastercard' | 'discover';
  isInternational: boolean;
  paymentType?:
    | 'applepay'
    | 'googlepay'
    | 'paypal'
    | 'credit_card'
    | 'bank_account'
    | 'plaid_bank_account';
}) => {
  if (!amount || !billingAgreements) {
    return 0;
  }

  // Compute ApplePay / GPay / PayPal based on highest fees
  const creditCardType =
    paymentType === 'googlepay' || paymentType === 'applepay' || paymentType === 'paypal'
      ? 'americanExpress'
      : cardType === 'american-express'
      ? 'americanExpress'
      : cardType === 'mastercard'
      ? 'master'
      : cardType;

  let transactionFee = 0;
  let aggregateRate = 0;

  billingAgreements?.forEach((billingAgreement) => {
    switch (paymentType) {
      case 'applepay':
      case 'googlepay':
      case 'credit_card': {
        if (creditCardType) {
          transactionFee += billingAgreement?.creditCardTransactionFees?.[creditCardType] ?? 0;
          aggregateRate += billingAgreement.creditCardRates[creditCardType];

          if (isInternational) {
            aggregateRate += billingAgreement.creditCardInternationalMarkupRates[creditCardType];
          }
        }

        break;
      }
      case 'plaid_bank_account':
      case 'bank_account': {
        transactionFee += billingAgreement.bankAccountTransactionFees.base;
        aggregateRate += billingAgreement.bankAccountRates.base;

        if (isInternational) {
          aggregateRate += billingAgreement.bankAccountInternationalMarkupRates.base;
        }

        break;
      }
      case 'paypal': {
        transactionFee += billingAgreement.paypalTransactionFees.base;
        aggregateRate += billingAgreement.paypalRates.base;

        if (isInternational) {
          aggregateRate += billingAgreement.paypalInternationalMarkupRates.base;
        }

        break;
      }
      default:
        break;
    }
  });

  return (amount + transactionFee) / (1 - aggregateRate) - amount;
};
